Load packages
We’ll start by loading the necessary packages. We use pak to ensure all required Delphi tools are installed.

if (!requireNamespace("pak", quietly = TRUE)) install.packages("pak")
pkgs &lt;- c(
  epidatr = "cmu-delphi/epidatr",
  epiprocess = "cmu-delphi/epiprocess"
)
if (any(missing &lt;- !vapply(names(pkgs), requireNamespace, quietly = TRUE, logical(1)))) {
  pak::pkg_install(pkgs[missing])
}

invisible(lapply(names(pkgs), library, character.only = TRUE))

